}

.pomo-mode-btn.active {
    background: var(--color-rose);
    color: white;
    box-shadow: 0 4px 12px var(--color-rose-glow);
}

/* Large Timer Circular Display */
.timer-display-ring {
    position: relative;
    width: 280px;
    height: 280px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 36px;
}

.ring-fill {
    transform: rotate(-90deg);
    transform-origin: 50% 50%;
    stroke-dasharray: 754; /* 2 * PI * 120 */
    stroke-dashoffset: 0;
    transition: stroke-dashoffset 0.1s linear;
}

.time-digits {
    position: absolute;
    font-family: var(--font-display);
    font-size: 4rem;
    font-weight: 700;
    letter-spacing: -1.5px;
    color: #ffffff;
    text-shadow: 0 0 20px rgba(255, 255, 255, 0.15);
}

.timer-controls {
    display: flex;
    gap: 20px;
    width: 100%;
    max-width: 320px;
}

.timer-controls .btn {
