    border-color: var(--color-indigo);
    box-shadow: inset 0 0 12px rgba(99, 102, 241, 0.05);
}

.sound-icon {
    font-size: 1.8rem;
    background: rgba(255, 255, 255, 0.03);
    width: 48px;
    height: 48px;
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 1px solid var(--border-light);
    transition: var(--transition-fast);
}

.sound-card.active .sound-icon {
    background: rgba(99, 102, 241, 0.15);
    border-color: rgba(99, 102, 241, 0.3);
    color: white;
}

.sound-details {
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.sound-title {
    font-weight: 600;
    font-size: 0.95rem;
    color: #ffffff;
}

.sound-desc {
    font-size: 0.75rem;
    color: var(--color-text-secondary);
}

/* Volume Slider styling */
.volume-container {
    border-top: 1px solid var(--border-light);
    padding-top: 18px;
}

.volume-label {
    display: block;
    font-size: 0.8rem;
    color: var(--color-text-secondary);
    margin-bottom: 8px;
    font-weight: 500;
}

.volume-slider-group {
    display: flex;
    align-items: center;
    gap: 12px;
