}

.volume-slider-group input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    width: 14px;
    height: 14px;
    border-radius: var(--radius-full);
    background: var(--color-indigo);
    box-shadow: 0 0 8px var(--color-indigo-glow);
