}


/* --- TAB 4: JOURNAL & MOOD --- */
.journal-container {
    padding-bottom: 24px;
}

.journal-grid {
    display: grid;
    grid-template-columns: 1.3fr 1fr;
    gap: 24px;
}

.mood-selector-label {
    font-size: 0.85rem;
    color: var(--color-text-secondary);
    font-weight: 500;
    margin-top: 18px;
    margin-bottom: 10px;
}

.mood-selector-group {
    display: flex;
    gap: 8px;
    margin-bottom: 24px;
}

.mood-btn {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 6px;
    background: rgba(255, 255, 255, 0.02);
    border: 1px solid var(--border-light);
    border-radius: 12px;
    padding: 10px 4px;
    cursor: pointer;
    transition: var(--transition-normal);
}

.mood-btn:hover {
    background: rgba(255, 255, 255, 0.04);
    border-color: rgba(255, 255, 255, 0.12);
}

.mood-btn .emoji {
    font-size: 1.4rem;
}

.mood-btn .label {
    font-size: 0.7rem;
    font-family: var(--font-primary);
    color: var(--color-text-secondary);
    font-weight: 500;
}

.mood-btn.active {
    background: rgba(99, 102, 241, 0.08);
    border-color: var(--color-indigo);
}

.mood-btn.active .label {
    color: white;
    font-weight: 600;
}

.textarea-group {
    margin-bottom: 24px;
}

.textarea-group textarea {
    width: 100%;
    background: rgba(255, 255, 255, 0.02);
    border: 1px solid var(--border-light);
    border-radius: 16px;
    padding: 16px 20px;
    color: #ffffff;
    font-family: var(--font-primary);
    font-size: 0.95rem;
    line-height: 1.6;
    resize: none;
    outline: none;
    transition: var(--transition-fast);
}

.textarea-group textarea:focus {
    border-color: var(--border-focus);
    background: rgba(99, 102, 241, 0.04);
}

.journal-history-card {
    display: flex;
    flex-direction: column;
    max-height: 580px;
}

.journal-history-list {
    display: flex;
    flex-direction: column;
    gap: 16px;
    overflow-y: auto;
    flex-grow: 1;
    padding-right: 4px;
}

/* Journal Entry Item */
.journal-item {
    background: rgba(255, 255, 255, 0.02);
    border: 1px solid var(--border-light);
    border-radius: 16px;
    padding: 16px 20px;
}

.journal-item-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 12px;
}

.journal-item-meta {
    display: flex;
    align-items: center;
    gap: 10px;
}

.journal-item-mood-badge {
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid var(--border-light);
    width: 32px;
    height: 32px;
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.journal-item-date {
    font-size: 0.8rem;
    color: var(--color-text-secondary);
    font-weight: 500;
}

.journal-item-body {
    font-size: 0.88rem;
    color: var(--color-text-primary);
    line-height: 1.6;
    word-break: break-word;
    white-space: pre-wrap;
}


/* --- TOAST SYSTEM --- */
.toast {
    position: fixed;
    bottom: 32px;
    right: 32px;
    background: rgba(18, 20, 36, 0.85);
    backdrop-filter: var(--glass-blur);
    -webkit-backdrop-filter: var(--glass-blur);
    border: 1px solid var(--border-light);
    box-shadow: var(--shadow-premium);
    padding: 14px 24px;
    border-radius: 12px;
    z-index: 999;
    transform: translateY(100px);
    opacity: 0;
    transition: transform 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275), opacity 0.4s ease;
    display: flex;
    align-items: center;
    gap: 12px;
}

.toast.show {
    transform: translateY(0);
    opacity: 1;
}

.toast::before {
    content: '⚡';
    color: var(--color-indigo);
    font-weight: bold;
}


