    // === TOAST SYSTEM ===
    function showToast(message) {
        dom.toastMessage.textContent = message;
        dom.toastNotification.classList.add('show');
        setTimeout(() => {
            dom.toastNotification.classList.remove('show');
        }, 3000);
    }

    // === SIDEBAR COLLAPSE LOGIC ===
    function setSidebarState(collapsed) {
        state.sidebarCollapsed = collapsed;
        localStorage.setItem('aura_sidebar_collapsed', JSON.stringify(collapsed));
        if (collapsed) {
            dom.appWrapper.classList.add('sidebar-collapsed');
        } else {
            dom.appWrapper.classList.remove('sidebar-collapsed');
        }
    }

    dom.sidebarToggleBtn.addEventListener('click', () => {
        setSidebarState(!state.sidebarCollapsed);
    });

