    setSidebarState(state.sidebarCollapsed);

    // === EDITABLE USERNAME SYSTEM ===
    function updateUsernameDisplay() {
        dom.displayUsername.textContent = state.username;
        dom.avatarCircle.textContent = state.username.charAt(0).toUpperCase() || 'U';
    }

    function startEditingUsername() {
        dom.displayUsername.style.display = 'none';
        dom.usernameEditInput.style.display = 'block';
        dom.usernameEditInput.value = state.username;
        dom.usernameEditInput.focus();
        dom.usernameEditInput.select();
    }

    function finishEditingUsername(save) {
        dom.displayUsername.style.display = 'block';
        dom.usernameEditInput.style.display = 'none';
        if (save) {
            const newName = dom.usernameEditInput.value.trim();
            if (newName) {
                state.username = newName;
                localStorage.setItem('aura_username', state.username);
                updateUsernameDisplay();
                updateClock();
                showToast(`Username updated to ${state.username}`);
            }
        }
    }

    dom.displayUsername.addEventListener('dblclick', startEditingUsername);
    dom.usernameEditInput.addEventListener('blur', () => finishEditingUsername(true));
    dom.usernameEditInput.addEventListener('keydown', (e) => {
        if (e.key === 'Enter') finishEditingUsername(true);
        if (e.key === 'Escape') finishEditingUsername(false);
    });

    updateUsernameDisplay();

    // === TIME & DATE UPDATE ===
    function updateClock() {
        const now = new Date();
        // Time
        let hours = now.getHours();
        let minutes = now.getMinutes();
        hours = hours < 10 ? '0' + hours : hours;
        minutes = minutes < 10 ? '0' + minutes : minutes;
        dom.timeWidget.textContent = `${hours}:${minutes}`;

        // Date
        const options = { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' };
        dom.dateDisplay.textContent = now.toLocaleDateString('en-US', options);

        // Greeting
        let greeting = "Welcome back";
        if (now.getHours() < 12) greeting = "Good morning";
        else if (now.getHours() < 17) greeting = "Good afternoon";
        else greeting = "Good evening";
        dom.greetingText.textContent = `${greeting}, ${state.username}`;
    }
    setInterval(updateClock, 10000);
    updateClock();

    // Streak tracker
    function updateStreak() {
        const todayStr = new Date().toDateString();
        if (state.lastActiveDate !== todayStr) {
            if (state.lastActiveDate) {
                const lastDate = new Date(state.lastActiveDate);
                const difference = Math.floor((new Date(todayStr) - lastDate) / (1000 * 60 * 60 * 24));
                if (difference === 1) {
                    state.streak += 1;
                } else if (difference > 1) {
                    state.streak = 1;
                }
            } else {
                state.streak = 1;
            }
            state.lastActiveDate = todayStr;
            localStorage.setItem('aura_streak', state.streak);
            localStorage.setItem('aura_last_active', state.lastActiveDate);
        }
        dom.focusStreak.textContent = `⚡ ${state.streak} day streak`;
    }
    updateStreak();

    // Random quote loader
    function loadQuote() {
        const idx = Math.floor(Math.random() * QUOTES.length);
        dom.quoteDisplay.textContent = `"${QUOTES[idx].text}"`;
        dom.quoteAuthor.textContent = `— ${QUOTES[idx].author}`;
    }
    loadQuote();

    // === TAB SYSTEM IMPLEMENTATION ===
    function switchTab(tabId) {
        state.activeTab = tabId;

        // Navigation items active class
        dom.navItems.forEach(item => {
            if (item.getAttribute('data-tab') === tabId) {
                item.classList.add('active');
            } else {
                item.classList.remove('active');
            }
        });

        // Tab panes display
        dom.tabPanes.forEach(pane => {
            if (pane.id === `tab-${tabId}-pane`) {
                pane.classList.add('active');
            } else {
                pane.classList.remove('active');
            }
        });

        // Specific actions on tab switch
        if (tabId === 'dashboard') {
            renderDashboard();
        }
        if (tabId === 'tasks') {
            renderTasks();
        }
    }

    dom.navItems.forEach(item => {
        item.addEventListener('click', () => {
            switchTab(item.getAttribute('data-tab'));
        });
    });

