    // === DASHBOARD MAIN RENDER ===
    function renderDashboard() {
        const totalTasks = state.tasks.length;
        const doneTasks = state.tasks.filter(t => t.status === 'done').length;
        const percent = totalTasks === 0 ? 0 : Math.round((doneTasks / totalTasks) * 100);

        dom.statsTodoCount.textContent = `${doneTasks}/${totalTasks}`;
        dom.statsFocusMins.textContent = `${state.timer.focusTimeToday}m`;

        const r64Circumference = 402.12;
        const dashboardOffset = r64Circumference - (percent / 100 * r64Circumference);
        dom.dashboardProgressRing.style.strokeDasharray = r64Circumference;
        dom.dashboardProgressRing.style.strokeDashoffset = dashboardOffset;
        dom.dashboardProgressPercent.textContent = `${percent}%`;

        dom.quickTasksContainer.innerHTML = '';
        const todayTasks = state.tasks.filter(t => t.status !== 'done').slice(0, 3);

        if (todayTasks.length === 0) {
            dom.quickTasksContainer.innerHTML = `
                <div class="empty-state">
                    <p>${totalTasks > 0 ? 'All tasks completed for today!' : 'No tasks for today. Start fresh!'}</p>
                </div>
