    // === WEB AUDIO ENGINE (AMBIENT FOCUS SOUNDS) ===
    function initAudio() {
        if (!state.audio.ctx) {
            state.audio.ctx = new (window.AudioContext || window.webkitAudioContext)();
            state.audio.gainNode = state.audio.ctx.createGain();
            state.audio.gainNode.gain.setValueAtTime(state.audio.volume, state.audio.ctx.currentTime);
            state.audio.gainNode.connect(state.audio.ctx.destination);
        }
        if (state.audio.ctx.state === 'suspended') {
            state.audio.ctx.resume();
        }
    }

    function createNoiseBuffer(duration = 2) {
        const bufferSize = state.audio.ctx.sampleRate * duration;
        const buffer = state.audio.ctx.createBuffer(1, bufferSize, state.audio.ctx.sampleRate);
        const data = buffer.getChannelData(0);

        let b0, b1, b2, b3, b4, b5, b6;
        b0 = b1 = b2 = b3 = b4 = b5 = b6 = 0.0;

        for (let i = 0; i < bufferSize; i++) {
            const white = Math.random() * 2 - 1;

            // Paul Kellet's pink noise
            b0 = 0.99886 * b0 + white * 0.0555179;
            b1 = 0.99332 * b1 + white * 0.0750759;
            b2 = 0.96900 * b2 + white * 0.1538520;
            b3 = 0.86650 * b3 + white * 0.3104856;
            b4 = 0.55000 * b4 + white * 0.5329522;
            b5 = -0.7616 * b5 - white * 0.0168980;

            const pink = b0 + b1 + b2 + b3 + b4 + b5 + b6 + white * 0.5362;
            b6 = white * 0.115926;

            data[i] = pink * 0.11;
        }
        return buffer;
    }

    function stopAmbientSound() {
        if (state.audio.nodes.sourceNode) {
            try { state.audio.nodes.sourceNode.stop(); } catch(e) {}
            state.audio.nodes.sourceNode.disconnect();
            state.audio.nodes.sourceNode = null;
        }
        if (state.audio.nodes.lfo) {
            try { state.audio.nodes.lfo.stop(); } catch(e) {}
            state.audio.nodes.lfo.disconnect();
            state.audio.nodes.lfo = null;
        }
        if (state.audio.nodes.filter) {
            state.audio.nodes.filter.disconnect();
            state.audio.nodes.filter = null;
        }
    }

    function playAmbientSound(type) {
        initAudio();
        stopAmbientSound();

        state.audio.activeSound = type;
        updateSoundUI(type);

        if (type === 'none') return;

        const ctx = state.audio.ctx;
        const noiseBuffer = createNoiseBuffer(3);
        const sourceNode = ctx.createBufferSource();
        sourceNode.buffer = noiseBuffer;
        sourceNode.loop = true;

        if (type === 'noise') {
            sourceNode.connect(state.audio.gainNode);
            sourceNode.start(0);
            state.audio.nodes.sourceNode = sourceNode;
        } 
        else if (type === 'rain') {
            const rainFilter = ctx.createBiquadFilter();
            rainFilter.type = 'lowpass';
            rainFilter.frequency.value = 850;

            const rainFilter2 = ctx.createBiquadFilter();
            rainFilter2.type = 'peaking';
            rainFilter2.frequency.value = 350;
            rainFilter2.Q.value = 1.0;
            rainFilter2.gain.value = 4.0;

            sourceNode.connect(rainFilter);
            rainFilter.connect(rainFilter2);
            rainFilter2.connect(state.audio.gainNode);

            sourceNode.start(0);
            state.audio.nodes.sourceNode = sourceNode;
            state.audio.nodes.filter = rainFilter;
        } 
        else if (type === 'wind') {
            const windFilter = ctx.createBiquadFilter();
            windFilter.type = 'bandpass';
            windFilter.frequency.value = 400;
            windFilter.Q.value = 2.0;

            const lfo = ctx.createOscillator();
            lfo.frequency.value = 0.08;

            const lfoGain = ctx.createGain();
            lfoGain.gain.value = 250;

            lfo.connect(lfoGain);
            lfoGain.connect(windFilter.frequency);

            sourceNode.connect(windFilter);
            windFilter.connect(state.audio.gainNode);

            lfo.start(0);
            sourceNode.start(0);

            state.audio.nodes.sourceNode = sourceNode;
            state.audio.nodes.lfo = lfo;
            state.audio.nodes.filter = windFilter;
        }
    }

    function updateSoundUI(type) {
        dom.soundCards.forEach(card => {
            if (card.getAttribute('data-sound') === type) {
                card.classList.add('active');
            } else {
                card.classList.remove('active');
            }
        });

        const pills = [dom.miniSoundNone, dom.miniSoundRain, dom.miniSoundNoise];
        pills.forEach(pill => {
            if (pill && pill.getAttribute('data-sound') === type) {
                pill.classList.add('active');
            } else if (pill) {
                pill.classList.remove('active');
            }
        });
    }

    function playSessionChime() {
        initAudio();
        const ctx = state.audio.ctx;
        const now = ctx.currentTime;

        const osc1 = ctx.createOscillator();
        const osc2 = ctx.createOscillator();
        const chimeGain = ctx.createGain();

        osc1.type = 'sine';
        osc1.frequency.setValueAtTime(523.25, now); // C5
        osc1.frequency.exponentialRampToValueAtTime(1046.50, now + 0.15); // Slide up to C6

        osc2.type = 'triangle';
        osc2.frequency.setValueAtTime(783.99, now); // G5

        chimeGain.gain.setValueAtTime(0.01, now);
        chimeGain.gain.linearRampToValueAtTime(0.3, now + 0.05);
        chimeGain.gain.exponentialRampToValueAtTime(0.001, now + 1.8);

        osc1.connect(chimeGain);
        osc2.connect(chimeGain);
        chimeGain.connect(ctx.destination);

        osc1.start(now);
        osc2.start(now);
        osc1.stop(now + 2.0);
        osc2.stop(now + 2.0);
    }

    dom.soundCards.forEach(card => {
        card.addEventListener('click', () => {
            const type = card.getAttribute('data-sound');
            playAmbientSound(type);
        });
    });

    const miniPills = [dom.miniSoundNone, dom.miniSoundRain, dom.miniSoundNoise];
    miniPills.forEach(pill => {
        if (pill) {
            pill.addEventListener('click', () => {
                const type = pill.getAttribute('data-sound');
                playAmbientSound(type);
            });
        }
    });

    dom.ambientVolume.addEventListener('input', (e) => {
        state.audio.volume = parseFloat(e.target.value);
        localStorage.setItem('aura_audio_volume', state.audio.volume);
        if (state.audio.gainNode) {
            state.audio.gainNode.gain.setValueAtTime(state.audio.volume, state.audio.ctx.currentTime);
        }
    });

    // Initialize volume slider position
    dom.ambientVolume.value = state.audio.volume;


    // === POMODORO COUNTDOWN ENGINE (WITH UPGRADED SETTINGS SLIDERS) ===

    // Sliders UI sync & State update functions
    function updateWorkDurationSetting(minutes) {
        state.timer.workDuration = minutes;
        localStorage.setItem('aura_duration_work', minutes);
        dom.valWorkDuration.textContent = `${minutes}m`;
        dom.inputWorkDuration.value = minutes;
        if (state.timer.mode === 'work') {
            resetTimer();
        }
    }

    function updateShortDurationSetting(minutes) {
        state.timer.shortDuration = minutes;
        localStorage.setItem('aura_duration_short', minutes);
        dom.valShortDuration.textContent = `${minutes}m`;
        dom.inputShortDuration.value = minutes;
        if (state.timer.mode === 'short') {
            resetTimer();
        }
    }

    function updateLongDurationSetting(minutes) {
        state.timer.longDuration = minutes;
        localStorage.setItem('aura_duration_long', minutes);
        dom.valLongDuration.textContent = `${minutes}m`;
        dom.inputLongDuration.value = minutes;
        if (state.timer.mode === 'long') {
            resetTimer();
        }
    }

    // Slider inputs event bindings
    dom.inputWorkDuration.addEventListener('input', (e) => updateWorkDurationSetting(parseInt(e.target.value)));
    dom.inputShortDuration.addEventListener('input', (e) => updateShortDurationSetting(parseInt(e.target.value)));
    dom.inputLongDuration.addEventListener('input', (e) => updateLongDurationSetting(parseInt(e.target.value)));

    // Load initial settings UI text
    updateWorkDurationSetting(state.timer.workDuration);
    updateShortDurationSetting(state.timer.shortDuration);
    updateLongDurationSetting(state.timer.longDuration);

    function setTimerMode(mode) {
        state.timer.mode = mode;
        let durationMinutes = 25;
        if (mode === 'work') durationMinutes = state.timer.workDuration;
        else if (mode === 'short') durationMinutes = state.timer.shortDuration;
        else if (mode === 'long') durationMinutes = state.timer.longDuration;

        state.timer.duration = durationMinutes * 60;
        state.timer.remaining = state.timer.duration;

        dom.pomoModeBtns.forEach(btn => {
            if (btn.getAttribute('data-mode') === mode) {
                btn.classList.add('active');
            } else {
                btn.classList.remove('active');
            }
        });

        pauseTimer();
        updateTimerDisplay();
    }

    function updateTimerDisplay() {
        const minutes = Math.floor(state.timer.remaining / 60);
        const seconds = state.timer.remaining % 60;
        const displayStr = `${minutes}:${seconds < 10 ? '0' + seconds : seconds}`;

        dom.pomoTimerDisplay.textContent = displayStr;
        dom.miniTimerDisplay.textContent = displayStr;

        // Tab Title update
        document.title = state.timer.isRunning ? `(${displayStr}) Aura | Focus` : `Aura | Personal Productivity Sanctuary`;

        // Circumference for r=120: 753.98
        const ringCircumference = 753.98;
        const progressFraction = state.timer.remaining / state.timer.duration;
        const ringOffset = ringCircumference * (1 - progressFraction);

        dom.pomoProgressRing.style.strokeDasharray = ringCircumference;
        dom.pomoProgressRing.style.strokeDashoffset = ringOffset;
    }

    function startTimer() {
        if (state.timer.isRunning) return;
        initAudio();

        state.timer.isRunning = true;
        dom.pomoPlayBtn.textContent = 'Pause';
        dom.pomoPlayBtn.classList.remove('btn-primary');
        dom.pomoPlayBtn.classList.add('btn-secondary');
        dom.miniPlayBtn.innerHTML = `
            <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2">
                <rect x="6" y="4" width="4" height="16"></rect>
                <rect x="14" y="4" width="4" height="16"></rect>
            </svg>
        `;

        state.timer.intervalId = setInterval(() => {
            state.timer.remaining--;

            if (state.timer.remaining <= 0) {
                timerCompleted();
            } else {
                updateTimerDisplay();
            }
        }, 1000);
    }

    function pauseTimer() {
        state.timer.isRunning = false;
        clearInterval(state.timer.intervalId);

        dom.pomoPlayBtn.textContent = 'Start';
        dom.pomoPlayBtn.classList.remove('btn-secondary');
        dom.pomoPlayBtn.classList.add('btn-primary');
        dom.miniPlayBtn.innerHTML = `
            <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2">
                <polygon points="5 3 19 12 5 21 5 3"></polygon>
            </svg>
        `;
        updateTimerDisplay();
    }

    function resetTimer() {
        pauseTimer();
        let durationMinutes = 25;
        if (state.timer.mode === 'work') durationMinutes = state.timer.workDuration;
        else if (state.timer.mode === 'short') durationMinutes = state.timer.shortDuration;
        else if (state.timer.mode === 'long') durationMinutes = state.timer.longDuration;

        state.timer.duration = durationMinutes * 60;
        state.timer.remaining = state.timer.duration;
        updateTimerDisplay();
    }

    function timerCompleted() {
        pauseTimer();
        playSessionChime();

        if (state.timer.mode === 'work') {
            const addedMinutes = state.timer.workDuration;
            state.timer.focusTimeToday += addedMinutes;
            localStorage.setItem('aura_focus_mins', state.timer.focusTimeToday);
            showToast(`Focus session completed! Great job focusing for ${addedMinutes} minutes.`);
            renderDashboard();
            setTimerMode('short'); // Auto-switch to break
        } else {
            showToast('Break completed! Ready to get back to work?');
            setTimerMode('work'); // Auto-switch to work
        }
    }

    // Timer Event Listeners
    dom.pomoPlayBtn.addEventListener('click', () => {
        if (state.timer.isRunning) pauseTimer();
        else startTimer();
    });

    dom.miniPlayBtn.addEventListener('click', () => {
        if (state.timer.isRunning) pauseTimer();
        else startTimer();
    });

    dom.pomoResetBtn.addEventListener('click', resetTimer);
    dom.miniResetBtn.addEventListener('click', resetTimer);

    dom.pomoModeBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            setTimerMode(btn.getAttribute('data-mode'));
        });
    });


    // === KEYBOARD SHORTCUTS MODAL BINDINGS ===
    function showShortcutsModal() {
        dom.shortcutsModal.style.display = 'flex';
        // Force reflow for opacity transition
        dom.shortcutsModal.offsetHeight;
        dom.shortcutsModal.classList.add('show');
    }

    function hideShortcutsModal() {
        dom.shortcutsModal.classList.remove('show');
        setTimeout(() => {
            dom.shortcutsModal.style.display = 'none';
        }, 300);
    }

    dom.openShortcutsBtn.addEventListener('click', showShortcutsModal);
    dom.closeShortcutsBtn.addEventListener('click', hideShortcutsModal);
    dom.shortcutsModal.addEventListener('click', (e) => {
        if (e.target === dom.shortcutsModal) hideShortcutsModal();
    });

    // Global keyboard listener
    window.addEventListener('keydown', (e) => {
        // Prevent triggers when typing in inputs/textareas
        const activeNode = document.activeElement.nodeName;
        if (activeNode === 'INPUT' || activeNode === 'TEXTAREA') {
            return;
        }

        // Spacebar -> Play/Pause Pomodoro
        if (e.key === ' ' || e.code === 'Space') {
            e.preventDefault();
            if (state.timer.isRunning) pauseTimer();
            else startTimer();
        }

        // Alt Keys mappings
        if (e.altKey) {
            switch (e.key.toLowerCase()) {
                case '1':
                    e.preventDefault();
                    switchTab('dashboard');
                    break;
                case '2':
                    e.preventDefault();
                    switchTab('tasks');
                    break;
                case '3':
                    e.preventDefault();
                    switchTab('pomodoro');
                    break;
                case '4':
                    e.preventDefault();
                    switchTab('journal');
                    break;
                case 'b':
                    e.preventDefault();
                    setSidebarState(!state.sidebarCollapsed);
                    break;
                case 'r':
                    e.preventDefault();
                    resetTimer();
                    showToast('Timer reset.');
                    break;
                case '?':
                    e.preventDefault();
                    showShortcutsModal();
                    break;
            }
        }
    });


    // === INITIALIZATION ===
    setTimerMode('work');
    renderTasks();
    renderJournal();
    renderDashboard();
});

/* ==========================================================================
   AURA DESIGN SYSTEM & STYLESHEET (UPGRADED RESPONSIVE EDITION)
   ========================================================================== */

/* 1. Global Variables & Tokens */
:root {
    /* Colors */
    --color-bg-base: #07080d;
    --color-bg-surface: rgba(18, 20, 36, 0.45);
    --color-bg-surface-hover: rgba(26, 29, 51, 0.65);
    --color-bg-card-header: rgba(255, 255, 255, 0.02);

    --color-text-primary: #f8fafc;
    --color-text-secondary: #94a3b8;
    --color-text-muted: #64748b;

    --color-indigo: #6366f1;
    --color-indigo-glow: rgba(99, 102, 241, 0.25);
    --color-emerald: #10b981;
    --color-emerald-glow: rgba(16, 185, 129, 0.2);
    --color-rose: #f43f5e;
    --color-rose-glow: rgba(244, 63, 94, 0.25);
    --color-amber: #f59e0b;
    --color-amber-glow: rgba(245, 158, 11, 0.2);

    --border-light: rgba(255, 255, 255, 0.07);
    --border-focus: rgba(99, 102, 241, 0.5);

    /* Layout & Styling */
    --radius-sm: 8px;
    --radius-md: 16px;
    --radius-lg: 24px;
    --radius-full: 9999px;

    --font-primary: 'Plus Jakarta Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    --font-display: 'Outfit', sans-serif;

    --transition-fast: 0.2s cubic-bezier(0.4, 0, 0.2, 1);
    --transition-normal: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    --transition-slow: 0.6s cubic-bezier(0.4, 0, 0.2, 1);

    --shadow-premium: 0 8px 32px 0 rgba(0, 0, 0, 0.37);
    --glass-blur: blur(20px);
}

/* 2. Reset & Base Setup */
*, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

html, body {
    width: 100%;
    height: 100%;
    overflow: hidden;
    background-color: var(--color-bg-base);
    color: var(--color-text-primary);
    font-family: var(--font-primary);
    font-size: 16px;
    line-height: 1.5;
    -webkit-font-smoothing: antialiased;
}

/* 3. Ambient Background Blobs */
.blob-container {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: -1;
    overflow: hidden;
    pointer-events: none;
    background: radial-gradient(circle at 50% 50%, #0d0f22 0%, #06070a 100%);
}

.blob {
    position: absolute;
    border-radius: var(--radius-full);
    filter: blur(140px);
    opacity: 0.25;
    mix-blend-mode: screen;
    animation: float-blob 20s infinite alternate ease-in-out;
}

.blob-1 {
    top: -10%;
    left: -10%;
    width: 50vw;
    height: 50vw;
    background: radial-gradient(circle, var(--color-indigo) 0%, transparent 70%);
    animation-duration: 25s;
}

.blob-2 {
    bottom: -10%;
    right: -10%;
    width: 60vw;
    height: 60vw;
    background: radial-gradient(circle, var(--color-rose) 0%, transparent 70%);
    animation-duration: 30s;
    animation-delay: -5s;
}

.blob-3 {
    top: 40%;
    left: 30%;
    width: 45vw;
    height: 45vw;
    background: radial-gradient(circle, var(--color-emerald) 0%, transparent 70%);
    animation-duration: 22s;
    animation-delay: -10s;
}

@keyframes float-blob {
    0% { transform: translate(0, 0) scale(1) rotate(0deg); }
    50% { transform: translate(5%, 10%) scale(1.1) rotate(180deg); }
    100% { transform: translate(-5%, -5%) scale(0.9) rotate(360deg); }
}

/* 4. App Container & Transitions */
.app-container {
    display: grid;
    grid-template-columns: 280px 1fr;
    width: 100vw;
    height: 100vh;
    padding: 24px;
    gap: 24px;
    box-sizing: border-box;
    transition: grid-template-columns var(--transition-normal);
}

.app-container.sidebar-collapsed {
    grid-template-columns: 80px 1fr;
}

/* Mobile Sidebar Mask Overlay */
.sidebar-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background: rgba(4, 5, 10, 0.4);
    backdrop-filter: blur(4px);
    -webkit-backdrop-filter: blur(4px);
    z-index: 8;
    opacity: 0;
    pointer-events: none;
    transition: opacity var(--transition-normal);
}

.sidebar-overlay.active {
    opacity: 1;
    pointer-events: auto;
}

/* 5. Sidebar Navigation */
.sidebar {
    background: var(--color-bg-surface);
    backdrop-filter: var(--glass-blur);
    -webkit-backdrop-filter: var(--glass-blur);
    border: 1px solid var(--border-light);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-premium);
    display: flex;
    flex-direction: column;
    padding: 32px 14px;
    z-index: 10;
    position: relative;
    transition: padding var(--transition-normal), transform var(--transition-normal);
}

.sidebar-toggle {
    position: absolute;
    top: 36px;
    right: -12px;
    background: rgba(18, 20, 36, 0.9);
    border: 1px solid var(--border-light);
    color: var(--color-text-primary);
    width: 26px;
    height: 26px;
    border-radius: var(--radius-full);
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    z-index: 20;
    box-shadow: 0 4px 10px rgba(0, 0, 0, 0.3);
    transition: transform var(--transition-normal), color var(--transition-fast);
}

.sidebar-toggle:hover {
    color: var(--color-indigo);
    border-color: rgba(99, 102, 241, 0.4);
}

.app-container.sidebar-collapsed .sidebar-toggle {
    right: 27px;
    transform: rotate(180deg);
}

.brand {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 48px;
    padding-left: 14px;
    overflow: hidden;
    white-space: nowrap;
}

.brand-logo {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 38px;
    height: 38px;
    min-width: 38px;
    background: linear-gradient(135deg, var(--color-indigo), var(--color-rose));
    color: var(--color-text-primary);
    border-radius: 10px;
    box-shadow: 0 4px 16px rgba(99, 102, 241, 0.35);
}

.brand-name {
    font-family: var(--font-display);
    font-weight: 700;
