}

/* Sidebar Footer */
.sidebar-footer {
    border-top: 1px solid var(--border-light);
    padding-top: 24px;
    overflow: hidden;
}

.user-profile {
    display: flex;
    align-items: center;
    gap: 12px;
    padding-left: 6px;
}

.avatar {
    width: 38px;
    height: 38px;
    min-width: 38px;
    border-radius: var(--radius-full);
    background: linear-gradient(135deg, #4f46e5, #06b6d4);
    display: flex;
    align-items: center;
