/* Collapsed Bindings */
.app-container.sidebar-collapsed .sidebar {
    padding: 32px 8px;
}

.app-container.sidebar-collapsed .brand-name,
.app-container.sidebar-collapsed .nav-label,
.app-container.sidebar-collapsed .user-info {
