    border-radius: 12px;
}

.app-container.sidebar-collapsed .user-profile {
    padding-left: 6px;
}


/* 6. Main Content Area & Layouts */
.main-content {
    display: grid;
    grid-template-rows: auto 1fr;
    gap: 24px;
    height: 100%;
    overflow: hidden;
}

/* Top Bar */
.top-bar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    background: var(--color-bg-surface);
    backdrop-filter: var(--glass-blur);
