    border-radius: 12px;
    border: 1px solid rgba(99, 102, 241, 0.2);
    text-shadow: 0 0 10px rgba(99, 102, 241, 0.3);
}

/* Content Body Scroll Track */
.content-body {
    position: relative;
    width: 100%;
    height: 100%;
    overflow-y: auto;
    padding-right: 4px;
}

/* Custom Scrollbar */
.content-body::-webkit-scrollbar,
.task-list::-webkit-scrollbar,
.journal-history-list::-webkit-scrollbar {
    width: 6px;
}

.content-body::-webkit-scrollbar-track,
.task-list::-webkit-scrollbar-track,
.journal-history-list::-webkit-scrollbar-track {
