}

.content-body::-webkit-scrollbar-thumb,
.task-list::-webkit-scrollbar-thumb,
.journal-history-list::-webkit-scrollbar-thumb {
    background: rgba(255, 255, 255, 0.05);
    border-radius: var(--radius-full);
    transition: var(--transition-fast);
}

.content-body::-webkit-scrollbar-thumb:hover,
.task-list::-webkit-scrollbar-thumb:hover,
.journal-history-list::-webkit-scrollbar-thumb:hover {
    background: rgba(255, 255, 255, 0.15);
}

/* Tab Management */
.tab-pane {
    display: none;
    opacity: 0;
    transform: translateY(12px);
    transition: opacity 0.4s ease, transform 0.4s ease;
    width: 100%;
    height: 100%;
}

.tab-pane.active {
    display: block;
    opacity: 1;
    transform: translateY(0);
}

/* Cards System */
.card {
    background: var(--color-bg-surface);
    backdrop-filter: var(--glass-blur);
    -webkit-backdrop-filter: var(--glass-blur);
    border: 1px solid var(--border-light);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-premium);
    padding: 24px;
    position: relative;
    overflow: hidden;
    transition: border-color var(--transition-normal), transform var(--transition-normal);
}

.card:hover {
    border-color: rgba(255, 255, 255, 0.15);
}

.card-title {
    font-family: var(--font-display);
    font-weight: 600;
    font-size: 1.15rem;
    margin-bottom: 18px;
    display: flex;
    align-items: center;
    gap: 8px;
    color: #ffffff;
}

.card-subtitle {
    font-size: 0.85rem;
    color: var(--color-text-secondary);
    margin-top: -12px;
    margin-bottom: 20px;
}

/* Buttons System */
.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    border: none;
    border-radius: 12px;
    font-family: var(--font-primary);
    font-weight: 600;
    cursor: pointer;
    transition: var(--transition-normal);
}

.btn-primary {
    background: linear-gradient(135deg, var(--color-indigo), #4f46e5);
    color: white;
    box-shadow: 0 4px 14px rgba(99, 102, 241, 0.3);
}

.btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(99, 102, 241, 0.5);
    background: linear-gradient(135deg, #7c3aed, var(--color-indigo));
}

.btn-secondary {
    background: rgba(255, 255, 255, 0.05);
    color: var(--color-text-primary);
    border: 1px solid var(--border-light);
}

.btn-secondary:hover {
    background: rgba(255, 255, 255, 0.1);
    border-color: rgba(255, 255, 255, 0.2);
}

.btn-icon {
    width: 42px;
    height: 42px;
    min-width: 42px;
    border-radius: 12px;
}

.btn-large {
    padding: 14px 28px;
    font-size: 1rem;
}

.btn-small {
    padding: 8px 14px;
    font-size: 0.8rem;
    border-radius: 8px;
}

.btn-text {
    background: none;
    border: none;
    color: var(--color-indigo);
    font-weight: 600;
    font-size: 0.85rem;
    cursor: pointer;
    transition: var(--transition-fast);
}

.btn-text:hover {
    color: #818cf8;
    text-shadow: 0 0 8px rgba(99,102,241,0.25);
}

.glow {
    position: relative;
}

.glow::after {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    border-radius: inherit;
    box-shadow: 0 0 15px var(--color-rose-glow);
    opacity: 0;
    transition: opacity var(--transition-normal);
    pointer-events: none;
}

.btn-primary.glow::after {
    box-shadow: 0 0 15px var(--color-indigo-glow);
}

.btn-primary.glow:hover::after {
    opacity: 1;
}

/* ==========================================================================
   TAB PANES: DETAILED MODULE STYLINGS
   ========================================================================== */

/* --- TAB 1: DASHBOARD GRID --- */
.dashboard-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 24px;
    padding-bottom: 24px;
}

.col-span-2 {
    grid-column: span 2;
}

/* Hero Quote Card */
.hero-card {
    background: linear-gradient(135deg, rgba(22, 26, 48, 0.6) 0%, rgba(10, 11, 21, 0.8) 100%);
    border: 1px solid rgba(99, 102, 241, 0.15);
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.hero-content {
    max-width: 65%;
    z-index: 2;
}

.quote-text {
    font-family: var(--font-primary);
    font-size: 1.2rem;
    font-weight: 400;
    line-height: 1.5;
    color: var(--color-text-primary);
    margin-top: 10px;
    font-style: italic;
}

.quote-author {
    display: block;
    font-size: 0.8rem;
    color: var(--color-indigo);
    font-weight: 600;
    margin-top: 12px;
    letter-spacing: 0.5px;
}

.hero-graphic {
    position: relative;
    width: 140px;
    height: 120px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.aurora-orb {
    width: 85px;
    height: 85px;
    border-radius: var(--radius-full);
    background: linear-gradient(135deg, var(--color-indigo), var(--color-rose));
    filter: blur(12px);
    opacity: 0.75;
    box-shadow: 0 0 40px rgba(99, 102, 241, 0.6);
    animation: pulse-orb 6s infinite alternate ease-in-out;
}

@keyframes pulse-orb {
    0% { transform: scale(1); filter: blur(12px); }
    100% { transform: scale(1.25); filter: blur(20px); opacity: 0.9; }
}

/* Progress Ring Visuals */
.progress-ring-container {
    position: relative;
    display: flex;
    justify-content: center;
    align-items: center;
    margin: 10px auto 20px;
}

.progress-ring-circle {
    transform: rotate(-90deg);
    transform-origin: 50% 50%;
    transition: stroke-dashoffset 0.6s ease;
}

.progress-ring-text {
    position: absolute;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
}

.progress-ring-text .percentage {
    font-family: var(--font-display);
    font-size: 2rem;
    font-weight: 700;
    color: var(--color-indigo);
    text-shadow: 0 0 10px rgba(99, 102, 241, 0.2);
}

.progress-ring-text .label {
    font-size: 0.7rem;
    color: var(--color-text-secondary);
    text-transform: uppercase;
    letter-spacing: 1.5px;
    margin-top: -2px;
}

.progress-stats {
    display: grid;
    grid-template-columns: 1fr 1fr;
    border-top: 1px solid var(--border-light);
    padding-top: 18px;
    text-align: center;
}

.progress-stats .stat-item:first-child {
    border-right: 1px solid var(--border-light);
}

.stat-val {
    display: block;
    font-family: var(--font-display);
    font-size: 1.2rem;
    font-weight: 600;
    color: #ffffff;
}

.stat-lbl {
    font-size: 0.75rem;
    color: var(--color-text-secondary);
}

/* Dashboard Task List Preview */
.card-header-actions {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 18px;
}

.card-header-actions .card-title {
    margin-bottom: 0;
}

.quick-tasks-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
    height: 190px;
    overflow-y: auto;
}

.quick-task-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    background: rgba(255, 255, 255, 0.02);
    border: 1px solid var(--border-light);
    border-radius: 12px;
    padding: 12px 16px;
    transition: var(--transition-fast);
}

.quick-task-item:hover {
    background: rgba(255, 255, 255, 0.04);
    border-color: rgba(255,255,255,0.12);
}

.quick-task-info {
    display: flex;
    align-items: center;
    gap: 12px;
    max-width: 80%;
}

.task-checkbox-style {
    width: 20px;
    height: 20px;
    border-radius: 6px;
    border: 2px solid var(--color-indigo);
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: var(--transition-fast);
}

.task-checkbox-style:hover {
    background: rgba(99, 102, 241, 0.25);
}

.task-checkbox-style.checked {
    background: var(--color-indigo);
    border-color: var(--color-indigo);
}

.task-checkbox-style.checked::after {
    content: '✓';
    color: white;
    font-size: 0.8rem;
    font-weight: bold;
}

.quick-task-title {
    font-size: 0.9rem;
    font-weight: 500;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.quick-task-item.done .quick-task-title {
    text-decoration: line-through;
    color: var(--color-text-muted);
}

.priority-indicator {
    width: 8px;
    height: 8px;
    border-radius: var(--radius-full);
}

.priority-indicator.high { background: var(--color-rose); }
.priority-indicator.medium { background: var(--color-amber); }
.priority-indicator.low { background: var(--color-indigo); }

/* Quick Focus Mini Widget */
.mini-pomo-widget {
    display: flex;
    align-items: center;
    justify-content: space-between;
    background: rgba(255,255,255,0.02);
    border: 1px solid var(--border-light);
    padding: 16px 20px;
    border-radius: 16px;
    margin-bottom: 16px;
}

.mini-pomo-timer {
    font-family: var(--font-display);
    font-size: 2.25rem;
    font-weight: 700;
    color: var(--color-rose);
    text-shadow: 0 0 12px var(--color-rose-glow);
    letter-spacing: -1px;
}

.mini-pomo-controls {
    display: flex;
    gap: 8px;
}

.sound-pills {
    display: flex;
    gap: 8px;
    justify-content: space-between;
}

.pill {
    flex-grow: 1;
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid var(--border-light);
    border-radius: var(--radius-full);
    padding: 8px;
    font-family: var(--font-primary);
    font-size: 0.75rem;
    color: var(--color-text-secondary);
    font-weight: 500;
    cursor: pointer;
    text-align: center;
    transition: var(--transition-fast);
}

.pill:hover {
    background: rgba(255, 255, 255, 0.08);
    color: var(--color-text-primary);
}

.pill.active {
    background: rgba(99, 102, 241, 0.15);
    border-color: var(--color-indigo);
    color: #ffffff;
}

/* Today's Mindset/Mood info */
.current-mood-status {
    display: flex;
    align-items: center;
    gap: 16px;
    background: rgba(255, 255, 255, 0.02);
    border: 1px solid var(--border-light);
    padding: 16px;
    border-radius: 16px;
    margin-bottom: 16px;
}

.current-mood-status .mood-icon {
    font-size: 2rem;
}

.current-mood-status .mood-text {
    font-weight: 600;
    font-size: 0.95rem;
    color: #ffffff;
}

.journal-preview {
    font-size: 0.85rem;
    color: var(--color-text-secondary);
    line-height: 1.6;
    font-style: italic;
    background: rgba(255, 255, 255, 0.01);
    padding: 12px;
    border-left: 2px solid var(--color-text-muted);
    border-radius: 0 8px 8px 0;
}

.empty-state {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: var(--color-text-muted);
    font-size: 0.85rem;
    text-align: center;
    padding: 24px;
}


/* --- TAB 2: TASKS BOARD --- */
.task-manager-container {
    display: flex;
    flex-direction: column;
    gap: 20px;
    padding-bottom: 24px;
}

/* Utility Card styling */
.utility-control-card {
    padding: 16px 24px;
}

.search-filter-wrapper {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 16px;
}

.search-bar-group {
    display: flex;
    align-items: center;
    background: rgba(255, 255, 255, 0.02);
    border: 1px solid var(--border-light);
    border-radius: 12px;
    padding: 10px 16px;
    width: 320px;
    gap: 12px;
    transition: var(--transition-fast);
}

.search-bar-group:focus-within {
    border-color: var(--border-focus);
    background: rgba(99,102,241,0.03);
}

.search-icon {
    color: var(--color-text-secondary);
}

.search-bar-group input {
    background: none;
    border: none;
    color: white;
    width: 100%;
    font-family: var(--font-primary);
    font-size: 0.9rem;
    outline: none;
}

.search-bar-group input::placeholder {
    color: var(--color-text-muted);
}

.filter-controls-group {
    display: flex;
    align-items: center;
    gap: 8px;
    flex-wrap: wrap;
}

.filter-label {
    font-size: 0.8rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: var(--color-text-secondary);
    margin-right: 6px;
}

.filter-pill {
    background: rgba(255, 255, 255, 0.02);
    border: 1px solid var(--border-light);
    color: var(--color-text-secondary);
    padding: 8px 14px;
    border-radius: var(--radius-full);
    font-size: 0.8rem;
    font-family: var(--font-primary);
    font-weight: 500;
    cursor: pointer;
    transition: var(--transition-fast);
}

.filter-pill:hover {
    background: rgba(255, 255, 255, 0.06);
    color: white;
}

.filter-pill.active {
    background: var(--color-indigo);
    border-color: var(--color-indigo);
    color: white;
    box-shadow: 0 2px 10px var(--color-indigo-glow);
}

#clear-done-tasks-btn {
    margin-left: 12px;
    transition: background var(--transition-fast), border-color var(--transition-fast);
}

#clear-done-tasks-btn:hover {
    background: rgba(244, 63, 94, 0.15);
    border-color: rgba(244, 63, 94, 0.3);
    color: var(--color-rose);
}

.task-input-card {
    padding: 16px 24px;
}

.task-form .input-group {
    display: flex;
    gap: 16px;
    align-items: center;
}

.task-form input[type="text"] {
    flex-grow: 1;
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid var(--border-light);
    border-radius: 12px;
    padding: 12px 18px;
    color: #ffffff;
    font-family: var(--font-primary);
    font-size: 0.95rem;
    transition: var(--transition-fast);
}

.task-form input[type="text"]:focus {
    outline: none;
    border-color: var(--border-focus);
    background: rgba(99, 102, 241, 0.04);
}

.task-form select {
    background: rgba(18, 20, 36, 0.8);
    border: 1px solid var(--border-light);
    border-radius: 12px;
    padding: 12px 18px;
    color: var(--color-text-secondary);
    font-family: var(--font-primary);
    font-size: 0.95rem;
    cursor: pointer;
    transition: var(--transition-fast);
    outline: none;
}

.task-form select:focus {
    border-color: var(--border-focus);
}

/* Mobile columns segmented navigator (hidden on desktop) */
.tasks-mobile-nav {
    display: none;
    background: rgba(10, 11, 20, 0.3);
    border: 1px solid var(--border-light);
    border-radius: var(--radius-md);
    padding: 4px;
    gap: 4px;
}

.task-mobile-tab {
    flex: 1;
    background: transparent;
    border: none;
    color: var(--color-text-secondary);
    padding: 10px;
    border-radius: 12px;
    font-size: 0.85rem;
    font-family: var(--font-primary);
    font-weight: 600;
    cursor: pointer;
    transition: var(--transition-fast);
}

.task-mobile-tab.active {
    background: var(--color-indigo);
    color: white;
    box-shadow: 0 4px 12px var(--color-indigo-glow);
}

.task-columns {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 24px;
    height: 520px;
}

.task-column {
    display: flex;
    flex-direction: column;
    background: rgba(10, 11, 20, 0.3);
    border: 1px solid var(--border-light);
    border-radius: 20px;
    padding: 18px;
    overflow: hidden;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 18px;
    padding: 0 4px;
}

.column-title {
    font-family: var(--font-display);
    font-weight: 600;
    font-size: 1.05rem;
}

.badge {
    padding: 4px 10px;
    font-size: 0.75rem;
    font-weight: 700;
    border-radius: var(--radius-full);
}

.badge-todo { background: rgba(99, 102, 241, 0.15); color: var(--color-indigo); }
.badge-progress { background: rgba(245, 158, 11, 0.15); color: var(--color-amber); }
.badge-done { background: rgba(16, 185, 129, 0.15); color: var(--color-emerald); }

.task-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
    flex-grow: 1;
    overflow-y: auto;
    padding-bottom: 12px;
}

/* Kanban Task Card */
.task-card {
    background: var(--color-bg-surface);
    border: 1px solid var(--border-light);
    border-radius: 14px;
    padding: 16px;
    cursor: grab;
    transition: transform var(--transition-fast), border-color var(--transition-fast), box-shadow var(--transition-fast);
    position: relative;
    user-select: none;
}

.task-card:hover {
    transform: translateY(-2px);
    border-color: rgba(255, 255, 255, 0.15);
    box-shadow: 0 6px 16px rgba(0, 0, 0, 0.25);
}

.task-card:active {
    cursor: grabbing;
}

.task-card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 12px;
}

.task-card-priority {
    font-size: 0.65rem;
    font-weight: 700;
    text-transform: uppercase;
    padding: 2px 8px;
    border-radius: 4px;
    letter-spacing: 0.5px;
}

.task-card-priority.high { background: rgba(244, 63, 94, 0.12); color: var(--color-rose); }
.task-card-priority.medium { background: rgba(245, 158, 11, 0.12); color: var(--color-amber); }
.task-card-priority.low { background: rgba(99, 102, 241, 0.12); color: var(--color-indigo); }

.task-card-actions {
    display: flex;
    gap: 4px;
}

.btn-card-action {
    background: none;
    border: none;
    color: var(--color-text-muted);
    cursor: pointer;
    padding: 4px;
    border-radius: 6px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    transition: var(--transition-fast);
}

.btn-card-action:hover {
    color: var(--color-text-primary);
    background: rgba(255, 255, 255, 0.05);
}

.btn-card-action.delete:hover {
    color: var(--color-rose);
    background: rgba(244, 63, 94, 0.1);
}

.task-card-title {
    font-size: 0.9rem;
    font-weight: 500;
    color: var(--color-text-primary);
    line-height: 1.4;
    word-break: break-word;
    border: 1px solid transparent;
    padding: 2px 0;
    cursor: text;
}

.task-card.done .task-card-title {
    text-decoration: line-through;
    color: var(--color-text-muted);
}

.task-title-edit-input {
    background: rgba(255,255,255,0.06);
    border: 1px solid var(--border-focus);
    border-radius: 6px;
    color: white;
    font-family: var(--font-primary);
    font-size: 0.9rem;
    width: 100%;
    padding: 2px 6px;
    outline: none;
}

.task-card-footer {
    margin-top: 14px;
    padding-top: 10px;
    border-top: 1px solid rgba(255, 255, 255, 0.03);
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.task-nav-actions {
    display: flex;
    gap: 6px;
    width: 100%;
    justify-content: flex-end;
}

.btn-nav-arrow {
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid var(--border-light);
    color: var(--color-text-secondary);
    border-radius: 6px;
    width: 24px;
    height: 24px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    font-size: 0.8rem;
    transition: var(--transition-fast);
}

.btn-nav-arrow:hover {
    background: rgba(255, 255, 255, 0.08);
    color: var(--color-text-primary);
    border-color: rgba(255, 255, 255, 0.15);
}


/* --- TAB 3: POMODORO SANCTUARY --- */
.pomodoro-sanctuary {
    padding-bottom: 24px;
}

.pomo-grid {
    display: grid;
    grid-template-columns: 1.2fr 1fr;
    gap: 24px;
}

.main-timer-card {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 40px;
}

.pomo-modes {
    display: flex;
    background: rgba(0, 0, 0, 0.2);
    border: 1px solid var(--border-light);
    border-radius: var(--radius-full);
    padding: 6px;
    margin-bottom: 36px;
}

.pomo-mode-btn {
    background: transparent;
    border: none;
    font-family: var(--font-primary);
    font-weight: 600;
    font-size: 0.85rem;
    color: var(--color-text-secondary);
    padding: 10px 20px;
    border-radius: var(--radius-full);
    cursor: pointer;
    transition: var(--transition-fast);
}

.pomo-mode-btn:hover {
    color: var(--color-text-primary);
}

.pomo-mode-btn.active {
    background: var(--color-rose);
    color: white;
    box-shadow: 0 4px 12px var(--color-rose-glow);
}

/* Large Timer Circular Display */
.timer-display-ring {
    position: relative;
    width: 280px;
    height: 280px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 36px;
}

.ring-svg {
    max-width: 100%;
    height: auto;
}

.ring-fill {
    transform: rotate(-90deg);
    transform-origin: 50% 50%;
    stroke-dasharray: 754;
    stroke-dashoffset: 0;
    transition: stroke-dashoffset 0.1s linear;
}

.time-digits {
    position: absolute;
    font-family: var(--font-display);
    font-size: 4rem;
    font-weight: 700;
    letter-spacing: -1.5px;
    color: #ffffff;
    text-shadow: 0 0 20px rgba(255, 255, 255, 0.15);
}

.timer-controls {
    display: flex;
    gap: 20px;
    width: 100%;
    max-width: 320px;
}

.timer-controls .btn {
    flex: 1;
}

/* Timer Configuration sliders */
.timer-config-column {
    display: flex;
    flex-direction: column;
    gap: 24px;
}

.timer-config-card {
    padding: 24px;
}

.config-sliders {
    display: flex;
    flex-direction: column;
    gap: 16px;
}

.slider-control-item {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.slider-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.slider-label {
    font-size: 0.85rem;
    font-weight: 600;
    color: var(--color-text-secondary);
}

.slider-value {
    font-size: 0.85rem;
    font-weight: 700;
    color: var(--color-rose);
}

.slider-control-item input[type="range"] {
    -webkit-appearance: none;
    height: 6px;
    border-radius: var(--radius-full);
    background: rgba(255, 255, 255, 0.07);
    outline: none;
    cursor: pointer;
    width: 100%;
}

.slider-control-item input[type="range"]::-webkit-slider-thumb {
