    }
}

/**
 * AURA PRODUCTIVITY SANCTUARY - INTERACTIVE LOGIC & WEB AUDIO ENGINE
 * (UPGRADED RESPONSIVE & MOBILE EDITION)
 * Persists data to localStorage, updates SVG UI, and synthesizes audio.
 */

document.addEventListener('DOMContentLoaded', () => {
    // === APPLICATION STATE ===
    const state = {
        activeTab: 'dashboard',
        tasks: JSON.parse(localStorage.getItem('aura_tasks')) || [],
        journal: JSON.parse(localStorage.getItem('aura_journal')) || [],
        streak: parseInt(localStorage.getItem('aura_streak')) || 0,
        lastActiveDate: localStorage.getItem('aura_last_active') || '',
        username: localStorage.getItem('aura_username') || 'Focus User',
        sidebarCollapsed: JSON.parse(localStorage.getItem('aura_sidebar_collapsed')) || false,

        // Task Page Filtering State
        taskFilter: 'all', // all, high, medium, low
        taskSearchQuery: '',
        activeMobileTaskColumn: 'todo', // todo, progress, done

        // Pomodoro State
        timer: {
            mode: 'work', // work, short, long
            workDuration: parseInt(localStorage.getItem('aura_duration_work')) || 25,
            shortDuration: parseInt(localStorage.getItem('aura_duration_short')) || 5,
            longDuration: parseInt(localStorage.getItem('aura_duration_long')) || 15,
            remaining: 25 * 60,
            isRunning: false,
            intervalId: null,
            focusTimeToday: parseInt(localStorage.getItem('aura_focus_mins')) || 0
        },

        // Audio Synthesis State
        audio: {
            ctx: null,
            volume: parseFloat(localStorage.getItem('aura_audio_volume')) ?? 0.5,
            activeSound: 'none', // none, rain, noise, wind
            nodes: {
                gainNode: null,
                sourceNode: null,
                lfo: null,
                filter: null
            }
        }
    };

    // Motivational Quotes
    const QUOTES = [
        { text: "Focus is a muscle, and you are building it every second.", author: "Aura Mindset" },
        { text: "Your mind is for having ideas, not holding them.", author: "David Allen" },
        { text: "Simplicity is the ultimate sophistication.", author: "Leonardo da Vinci" },
        { text: "Deep work is not a chore; it is an act of creation.", author: "Cal Newport" },
        { text: "Be silent and let your progress speak for itself.", author: "Sanctuary Guide" },
        { text: "One focus at a time. The rest can wait.", author: "Aura Guide" }
    ];

    // === DOM ELEMENTS ===
    const dom = {
        // Wrapper for collapsed state
        appWrapper: document.getElementById('app-wrapper'),
        sidebarToggleBtn: document.getElementById('sidebar-toggle-btn'),
        mainSidebar: document.getElementById('main-sidebar'),
        sidebarOverlayMask: document.getElementById('sidebar-overlay-mask'),

        // Navigation
        navItems: document.querySelectorAll('.nav-item'),
        tabPanes: document.querySelectorAll('.tab-pane'),
        btnQuickTaskTab: document.getElementById('btn-quick-task-tab'),

        // Date / Time / Profile
        greetingText: document.getElementById('greeting-text'),
        dateDisplay: document.getElementById('date-display'),
        timeWidget: document.getElementById('time-widget'),
        focusStreak: document.getElementById('focus-streak'),
        displayUsername: document.getElementById('display-username'),
        usernameEditInput: document.getElementById('username-edit-input'),
        avatarCircle: document.getElementById('avatar-circle'),

        // Dashboard Widgets
        dashboardProgressRing: document.getElementById('dashboard-progress-ring'),
        dashboardProgressPercent: document.getElementById('dashboard-progress-percent'),
        statsTodoCount: document.getElementById('stats-todo-count'),
        statsFocusMins: document.getElementById('stats-focus-mins'),
        quoteDisplay: document.getElementById('quote-display'),
        quoteAuthor: document.getElementById('quote-author'),
        quickTasksContainer: document.getElementById('quick-tasks-container'),
        currentMoodStatus: document.getElementById('current-mood-status'),
        journalPreview: document.getElementById('journal-preview'),

        // Tasks Page Controls
        taskSearchInput: document.getElementById('task-search-input'),
        filterPills: document.querySelectorAll('.filter-pill'),
        clearDoneTasksBtn: document.getElementById('clear-done-tasks-btn'),
        taskForm: document.getElementById('task-form'),
        taskTitleInput: document.getElementById('task-title-input'),
        taskPriorityInput: document.getElementById('task-priority-input'),
        todoList: document.getElementById('todo-list'),
        progressList: document.getElementById('progress-list'),
        doneList: document.getElementById('done-list'),
        todoBadge: document.getElementById('todo-badge'),
        progressBadge: document.getElementById('progress-badge'),
        doneBadge: document.getElementById('done-badge'),
        tasksMobileNav: document.getElementById('tasks-mobile-nav'),
        mobileTaskTabs: document.querySelectorAll('.task-mobile-tab'),
        taskColumns: document.querySelectorAll('.task-column'),

        // Mini Pomodoro
        miniTimerDisplay: document.getElementById('mini-timer-display'),
        miniPlayBtn: document.getElementById('mini-play-btn'),
        miniResetBtn: document.getElementById('mini-reset-btn'),
        miniSoundNone: document.getElementById('mini-sound-none'),
        miniSoundRain: document.getElementById('mini-sound-rain'),
        miniSoundNoise: document.getElementById('mini-sound-noise'),

        // Pomodoro Page Settings & Sliders
        pomoTimerDisplay: document.getElementById('pomo-timer-display'),
        pomoProgressRing: document.getElementById('pomo-progress-ring'),
        pomoPlayBtn: document.getElementById('pomo-play-btn'),
        pomoResetBtn: document.getElementById('pomo-reset-btn'),
        pomoModeBtns: document.querySelectorAll('.pomo-mode-btn'),

        inputWorkDuration: document.getElementById('input-work-duration'),
        inputShortDuration: document.getElementById('input-short-duration'),
        inputLongDuration: document.getElementById('input-long-duration'),
        valWorkDuration: document.getElementById('val-work-duration'),
        valShortDuration: document.getElementById('val-short-duration'),
        valLongDuration: document.getElementById('val-long-duration'),

        soundCards: document.querySelectorAll('.sound-card'),
        ambientVolume: document.getElementById('ambient-volume'),

        // Journal Page
        journalForm: document.getElementById('journal-form'),
        moodBtns: document.querySelectorAll('.mood-btn'),
        journalTextInput: document.getElementById('journal-text-input'),
        journalHistoryContainer: document.getElementById('journal-history-container'),

        // Shortcuts Modal
        openShortcutsBtn: document.getElementById('open-shortcuts-btn'),
        shortcutsModal: document.getElementById('shortcuts-modal'),
        closeShortcutsBtn: document.getElementById('close-shortcuts-btn'),

        // Notification Toast
        toastNotification: document.getElementById('toast-notification'),
        toastMessage: document.getElementById('toast-message')
    };

    // === TOAST SYSTEM ===
    function showToast(message) {
        dom.toastMessage.textContent = message;
        dom.toastNotification.classList.add('show');
        setTimeout(() => {
            dom.toastNotification.classList.remove('show');
        }, 3000);
    }

    // === SIDEBAR COLLAPSE & MOBILE DRAWER LOGIC ===
    function isMobileView() {
        return window.innerWidth <= 768;
    }

    function setSidebarState(collapsed) {
        state.sidebarCollapsed = collapsed;
        localStorage.setItem('aura_sidebar_collapsed', JSON.stringify(collapsed));

        if (collapsed) {
            dom.appWrapper.classList.add('sidebar-collapsed');
        } else {
            dom.appWrapper.classList.remove('sidebar-collapsed');
        }
    }

    function toggleMobileDrawer(open) {
        if (open) {
            dom.mainSidebar.classList.add('open');
            dom.sidebarOverlayMask.classList.add('active');
        } else {
            dom.mainSidebar.classList.remove('open');
            dom.sidebarOverlayMask.classList.remove('active');
        }
    }

    dom.sidebarToggleBtn.addEventListener('click', () => {
        if (isMobileView()) {
            const isOpen = dom.mainSidebar.classList.contains('open');
            toggleMobileDrawer(!isOpen);
        } else {
            setSidebarState(!state.sidebarCollapsed);
        }
    });

    dom.sidebarOverlayMask.addEventListener('click', () => {
        toggleMobileDrawer(false);
    });

    // Close mobile drawer upon choosing a navigation tab
    dom.navItems.forEach(item => {
        item.addEventListener('click', () => {
            if (isMobileView()) {
                toggleMobileDrawer(false);
            }
        });
    });

    // Initialize sidebar state based on storage/view
    if (!isMobileView()) {
        setSidebarState(state.sidebarCollapsed);
    }

    // Handle viewport resize transitions
    window.addEventListener('resize', () => {
        if (!isMobileView()) {
            toggleMobileDrawer(false);
            setSidebarState(state.sidebarCollapsed);
        } else {
            dom.appWrapper.classList.remove('sidebar-collapsed');
        }
        updateTimerDisplay(); // Recalculate progress ring size based on size change
    });


    // === EDITABLE USERNAME SYSTEM ===
    function updateUsernameDisplay() {
        dom.displayUsername.textContent = state.username;
