    // === TASK BOARD CONTROL ACTIONS ===
    function saveTasks() {
        localStorage.setItem('aura_tasks', JSON.stringify(state.tasks));
        renderTasks();
        renderDashboard();
    }

    function createTask(title, priority = 'medium') {
        const task = {
            id: 'task_' + Date.now() + '_' + Math.floor(Math.random() * 1000),
            title,
            priority,
            status: 'todo',
            createdAt: new Date().toISOString()
        };
        state.tasks.push(task);
        saveTasks();
        showToast('Focus task added!');
    }

    function deleteTask(id) {
        state.tasks = state.tasks.filter(t => t.id !== id);
        saveTasks();
        showToast('Task removed.');
    }

    function moveTask(id, targetStatus) {
        const task = state.tasks.find(t => t.id === id);
        if (task) {
            task.status = targetStatus;
            saveTasks();
            showToast(`Task moved to ${targetStatus === 'progress' ? 'In Progress' : targetStatus === 'done' ? 'Completed' : 'To Do'}`);
        }
    }

    function startEditingTask(taskCard, task) {
        const titleEl = taskCard.querySelector('.task-card-title');
        titleEl.style.display = 'none';

        const editInput = document.createElement('input');
        editInput.type = 'text';
        editInput.className = 'task-title-edit-input';
        editInput.value = task.title;
        taskCard.insertBefore(editInput, titleEl.nextSibling);
        editInput.focus();
        editInput.select();

        function finishEditing(save) {
            editInput.remove();
            titleEl.style.display = 'block';
            if (save) {
                const newTitle = editInput.value.trim();
                if (newTitle && newTitle !== task.title) {
                    task.title = newTitle;
                    saveTasks();
                    showToast('Task title updated!');
                }
            }
        }

        editInput.addEventListener('blur', () => finishEditing(true));
        editInput.addEventListener('keydown', (e) => {
            if (e.key === 'Enter') finishEditing(true);
            if (e.key === 'Escape') finishEditing(false);
            e.stopPropagation();
        });
    }

    // Render task board lists
    function renderTasks() {
        dom.todoList.innerHTML = '';
        dom.progressList.innerHTML = '';
        dom.doneList.innerHTML = '';

        let counts = { todo: 0, progress: 0, done: 0 };
        const priorityWeight = { high: 3, medium: 2, low: 1 };

        let filteredTasks = state.tasks.filter(task => {
            const matchesSearch = task.title.toLowerCase().includes(state.taskSearchQuery.toLowerCase());
            const matchesPriority = state.taskFilter === 'all' || task.priority === state.taskFilter;
            return matchesSearch && matchesPriority;
        });

        filteredTasks.sort((a, b) => priorityWeight[b.priority] - priorityWeight[a.priority]);

        filteredTasks.forEach(task => {
            counts[task.status]++;
            const taskEl = document.createElement('div');
            taskEl.className = `task-card ${task.status === 'done' ? 'done' : ''}`;
            taskEl.setAttribute('id', task.id);
            taskEl.setAttribute('draggable', 'true');

            taskEl.innerHTML = `
                <div class="task-card-header">
                    <span class="task-card-priority ${task.priority}">${task.priority}</span>
                    <div class="task-card-actions">
                        <button class="btn-card-action delete" data-id="${task.id}" title="Delete Task">
                            <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2">
                                <polyline points="3 6 5 6 21 6"></polyline>
                                <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                            </svg>
                        </button>
                    </div>
                </div>
                <div class="task-card-title" title="Double click to edit">${escapeHTML(task.title)}</div>
                <div class="task-card-footer">
                    <div class="task-nav-actions">
                        ${task.status !== 'todo' ? `
                            <button class="btn-nav-arrow btn-prev" data-id="${task.id}" data-target="${task.status === 'done' ? 'progress' : 'todo'}" title="Move back">
                                ◀
                            </button>
                        ` : ''}
                        ${task.status !== 'done' ? `
                            <button class="btn-nav-arrow btn-next" data-id="${task.id}" data-target="${task.status === 'todo' ? 'progress' : 'done'}" title="Move forward">
                                ▶
                            </button>
                        ` : ''}
                    </div>
                </div>
            `;

            taskEl.querySelector('.task-card-title').addEventListener('dblclick', () => {
                startEditingTask(taskEl, task);
            });

            taskEl.addEventListener('dragstart', (e) => {
                e.dataTransfer.setData('text/plain', task.id);
                taskEl.style.opacity = '0.5';
